# V2.0 Framework Setup Script - Windows (Standalone Generator)
# Generated by /script command
# Run: .\setup-v2framework-win.ps1

$ErrorActionPreference = "Stop"
$TargetDir = "v2framework"

Write-Host "=== V2.0 Framework Setup (Windows) ===" -ForegroundColor Cyan

$scriptPath = $PSScriptRoot
$targetPath = Join-Path $scriptPath $TargetDir

if (Test-Path $targetPath) {
    Write-Host "Directory exists, removing..." -ForegroundColor Yellow
    Remove-Item -Recurse -Force $targetPath
}
Write-Host "Creating directory: $targetPath" -ForegroundColor Green
New-Item -ItemType Directory -Path $targetPath -Force | Out-Null

function Create-Dir {
    param([string]$path)
    $fullPath = Join-Path $targetPath $path
    New-Item -ItemType Directory -Path $fullPath -Force | Out-Null
    Write-Host "  [Folder] Created: $path" -ForegroundColor DarkGray
}

function Create-File {
    param([string]$path, [string]$content)
    $fullPath = Join-Path $targetPath $path
    $parentDir = Split-Path $fullPath
    
    if (-not (Test-Path $parentDir)) {
        New-Item -ItemType Directory -Path $parentDir -Force | Out-Null
    }
    
    $utf8NoBom = New-Object System.Text.UTF8Encoding $False
    [System.IO.File]::WriteAllText($fullPath, $content, $utf8NoBom)
    Write-Host "  [File]   Created: $path" -ForegroundColor Gray
}

Write-Host "`nGenerating Framework Structure..." -ForegroundColor Cyan

Create-Dir ".vibe\rules"
Create-Dir ".vibe\memory"
Create-Dir ".vibe\mcp_factory\template"
Create-Dir "docs\PRD"
Create-Dir "sandbox\test_environment"

